import { BookingRecord } from '../types';

const AdminPanel: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [activeTab, setActiveTab] = useState<'bookings' | 'features' | 'gallery'>('bookings');

  // Real DB Data
  const [dbBookings, setDbBookings] = useState<BookingRecord[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const { features, updateFeature, galleryImages, updateGallery } = useData();

  const fetchBookings = async () => {
    setIsLoading(true);
    try {
      const res = await fetch('api/get_bookings.php');
      const data = await res.json();
      // Map DB fields to TypeScript Interface if necessary, 
      // though PHP returns fields that mostly match, `id` in BookingRecord is string (using booking_code)
      // We map DB `booking_code` to TS `id` for consistency with frontend logic
      const mappedData = Array.isArray(data) ? data.map((b: any) => ({
        ...b,
        id: b.booking_code, // Use unique code as ID
        date: new Date(b.start).toLocaleDateString(),
        time: new Date(b.start).toLocaleTimeString(),
        totalPrice: parseFloat(b.price)
      })) : [];
      setDbBookings(mappedData);
    } catch (error) {
      console.error("Failed to fetch bookings", error);
    } finally {
      setIsLoading(false);
