                              {booking.status}
                            </span>
                          </td>
                          <td className="p-4 flex gap-2">
                            {booking.status === 'Pending' && (
                              <>
                                <button 
                                  onClick={() => handleUpdateStatus(booking.row_id, 'Approved')}
