                      <button 
                        onClick={() => triggerUpload('hero')}
                        className="bg-emerald-500 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-emerald-600 shadow-lg transform hover:scale-105 transition-all"
                      >
                        <Upload size={20} /> Upload New Banner
                      </button>
                    </div>
                  </div>
                  <p className="mt-4 text-sm text-gray-500 dark:text-gray-400 text-center">
                    This image appears as the large banner on the Home page. Recommended size: 1920x1080.
                  </p>
                </div>
              </section>

              {/* Testimonials Section */}
              <section>
                <h3 className="text-2xl font-bold mb-6 text-gray-800 dark:text-white flex items-center gap-2">
                  <Edit2 className="text-emerald-500" /> Client Reviews
                </h3>
                <div className="grid md:grid-cols-3 gap-6">
                  {testimonials.map((testimonial, idx) => (
                    <div key={idx} className="bg-white/30 dark:bg-black/20 p-6 rounded-2xl border border-white/10 relative">
                      <div className="flex justify-center mb-4">
                        <div className="relative w-24 h-24 group">
                          <img 
                            src={testimonial.avatar} 
                            alt="Client" 
                            className="w-full h-full rounded-full object-cover border-4 border-emerald-500/20"
                          />
                          <button 
                            onClick={() => triggerUpload('testimonial', idx)}
                            className="absolute inset-0 flex items-center justify-center bg-black/50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity text-white"
                          >
                            <Upload size={18} />
                          </button>
                        </div>
                      </div>

                      <div className="space-y-3">
                         <div>
                           <label className="text-xs font-bold text-gray-500 uppercase">Name</label>
                           <input 
                             type="text" 
                             value={testimonial.name}
                             onChange={(e) => handleTestimonialChange(idx, 'name', e.target.value)}
                             className="w-full bg-transparent border-b border-gray-400 focus:border-emerald-500 outline-none py-1 font-bold text-gray-800 dark:text-white"
                           />
                         </div>
                         <div>
                           <label className="text-xs font-bold text-gray-500 uppercase">Role</label>
                           <input 
                             type="text" 
                             value={testimonial.role}
                             onChange={(e) => handleTestimonialChange(idx, 'role', e.target.value)}
                             className="w-full bg-transparent border-b border-gray-400 focus:border-emerald-500 outline-none py-1 text-sm text-emerald-600"
                           />
                         </div>
                         <div>
                           <label className="text-xs font-bold text-gray-500 uppercase">Comment</label>
                           <textarea 
                             rows={3}
                             value={testimonial.comment}
                             onChange={(e) => handleTestimonialChange(idx, 'comment', e.target.value)}
                             className="w-full bg-transparent border border-gray-400/30 rounded p-2 focus:border-emerald-500 outline-none text-sm text-gray-600 dark:text-gray-300 mt-1 resize-none"
                           />
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          )}
        </GlassCard>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { GlassCard, GlassButton } from './GlassUI';
import { BookingState, VenueType, BookingRecord } from '../types';
import { Calendar, Clock, User, CheckCircle, AlertCircle, Loader2, RefreshCw, ChevronLeft, ChevronRight, Download, Printer, TreePalm } from 'lucide-react';
import { useData } from '../context/DataContext';
import { supabase } from '../lib/supabase';
import html2canvas from 'html2canvas';

const VENUES: { type: VenueType; price: number; unit: string }[] = [
  { type: 'Football Pitch', price: 8000, unit: '/hour' },
  { type: 'Courtyard', price: 100000, unit: '/day' },
  { type: 'Palm Garden', price: 100000, unit: '/day' },
  { type: 'Kids Playground', price: 200, unit: '/person' },
];

const Booking: React.FC = () => {
  const { addBooking } = useData();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState('');
  const [bookingCode, setBookingCode] = useState('');

  // Availability State
  const [existingBookings, setExistingBookings] = useState<any[]>([]);
  const [loadingAvailability, setLoadingAvailability] = useState(false);

  // Calendar View State
  const [viewDate, setViewDate] = useState(new Date());

  // Helper to get local YYYY-MM-DD string
  const getLocalDateString = (date: Date) => {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  };

  const [formData, setFormData] = useState<BookingState>({
    name: '',
    email: '',
    phone: '',
    venue: 'Football Pitch',
    date: getLocalDateString(new Date()), // Default to today
    endDate: '',
    time: '',
    duration: 1,
    guests: { adults: 0, children: 0 },
    message: ''
  });

  const [totalPrice, setTotalPrice] = useState(0);

  // Fetch existing bookings when Venue changes to show availability
  useEffect(() => {
    const fetchAvailability = async () => {
      setLoadingAvailability(true);
      try {
        // Fetch bookings starting from beginning of today to ensure calendar is accurate
        const today = new Date();
        today.setHours(0, 0, 0, 0);

        const { data, error } = await supabase
          .from('bookings')
          .select('start_time, end_time, status')
          .eq('venue', formData.venue)
          .neq('status', 'Rejected') // Ignore rejected bookings
          .gte('start_time', today.toISOString()); // Bookings from today onwards

        if (error) throw error;
        setExistingBookings(data || []);
      } catch (err) {
        console.error("Error fetching availability:", err);
      } finally {
        setLoadingAvailability(false);
      }
    };

    fetchAvailability();
  }, [formData.venue]);

  useEffect(() => {
    // Pricing Logic
    const selectedVenue = VENUES.find(v => v.type === formData.venue);
    if (!selectedVenue) return;

    let price = 0;
    if (formData.venue === 'Football Pitch') {
      price = selectedVenue.price * (formData.duration || 1);
    } else if (formData.venue === 'Kids Playground') {
       // 200 naira gate fee per individual (adults + children)
       const totalGuests = (formData.guests?.children || 0) + (formData.guests?.adults || 0);
       price = totalGuests * selectedVenue.price;
    } else {
      // Per day calculation for Courtyard/Palm Garden
      let days = 1;
      if (formData.date && formData.endDate) {
        const start = new Date(formData.date);
        const end = new Date(formData.endDate);
        const diffTime = Math.abs(end.getTime() - start.getTime());
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; // +1 to include start day
        days = diffDays > 0 ? diffDays : 1;
      }
      price = selectedVenue.price * days;
    }
    setTotalPrice(price);
  }, [formData]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;

    // Sanitize Phone Number
    if (name === 'phone') {
      const sanitizedValue = value.replace(/[^0-9+\-\s()]/g, '');
      setFormData(prev => ({ ...prev, [name]: sanitizedValue }));
      return;
    }

    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleGuestChange = (type: 'adults' | 'children', val: number) => {
    setFormData(prev => ({
      ...prev,
      guests: { ...prev.guests!, [type]: Math.max(0, val) }
    }));
  };

  const checkConflict = async (start: string, end: string) => {
    // Check database for overlaps
    const { data, error } = await supabase
      .from('bookings')
      .select('id')
      .eq('venue', formData.venue)
      .neq('status', 'Rejected')
      .lt('start_time', end) // Existing Start < New End
      .gt('end_time', start); // Existing End > New Start

    if (error) throw error;
    return data && data.length > 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setSubmitError('');

    try {
      // 1. Time Calculation
      let startDateTime = '';
      let stopDateTime = '';

      if (formData.venue === 'Football Pitch') {
        if (!formData.time || !formData.date) {
          throw new Error('Please select both date and time.');
        }

        const isoStart = `${formData.date}T${formData.time}:00`;
        const startDateObj = new Date(isoStart);

        if (isNaN(startDateObj.getTime())) {
          throw new Error("Invalid Date or Time selected");
        }

        startDateTime = startDateObj.toISOString();

        // Calculate Stop based on duration
        const durationHours = formData.duration || 1;
        const stopDateObj = new Date(startDateObj.getTime() + durationHours * 60 * 60 * 1000);
        stopDateTime = stopDateObj.toISOString();

      } else {
        if (!formData.date) {
           throw new Error('Please select a start date.');
        }
        // Set to start of day for accurate full-day locking
        startDateTime = new Date(`${formData.date}T00:00:00`).toISOString();

        const endDate = formData.endDate || formData.date;
        // Set to end of day
        stopDateTime = new Date(`${endDate}T23:59:59`).toISOString();
      }

      // 2. Conflict Check (Server Side)
      const hasConflict = await checkConflict(startDateTime, stopDateTime);
      if (hasConflict) {
        throw new Error(
          formData.venue === 'Football Pitch' 
            ? "This time slot is already booked. Please choose another time." 
            : "This date is already fully booked. Please check availability."
        );
      }

      // 3. Generate Booking Code
      const code = `JK-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

      // 4. Insert into Supabase
      const { error } = await supabase
        .from('bookings')
        .insert([
          {
            booking_code: code,
            name: formData.name,
            email: formData.email,
            phone: formData.phone,
            venue: formData.venue,
            start_time: startDateTime,
            end_time: stopDateTime,
            duration: formData.duration || 0,
            guests_adults: formData.guests?.adults || 0,
            guests_children: formData.guests?.children || 0,
            price: totalPrice,
            message: formData.message,
            status: 'Pending'
          }
        ]);

      if (error) {
        console.error('Supabase Error:', error);
        throw new Error(error.message || 'Database insert failed.');
      }

      // 5. Success State (No Email)
      setBookingCode(code);
      setStep(3);

      addBooking({
        ...formData,
        id: code,
        status: 'Pending',
        submissionDate: new Date().toISOString(),
        totalPrice: totalPrice
      });

    } catch (error: any) {
      console.error('Submission Error:', error);
      let msg = error.message || 'An unexpected error occurred.';
      if (msg.includes('apikey')) {
        msg = 'Database configuration missing. Please check connection.';
      }
      setSubmitError(msg);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const handleDownload = async () => {
    const element = document.getElementById('receipt-card');
    if (element) {
      try {
        const canvas = await html2canvas(element, {
          backgroundColor: '#ffffff',
          scale: 2 // Higher resolution
        });
        const data = canvas.toDataURL('image/png');
        const link = document.createElement('a');
        link.href = data;
        link.download = `JK_Receipt_${bookingCode}.png`;
        link.click();
      } catch (error) {
        console.error("Failed to generate image", error);
        alert("Could not generate receipt image. Please try the Print option.");
      }
    }
  };

  // --- Calendar Navigation Helpers ---
  const handlePrevMonth = () => {
    setViewDate(prev => new Date(prev.getFullYear(), prev.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setViewDate(prev => new Date(prev.getFullYear(), prev.getMonth() + 1, 1));
  };

  // --- Render Full Month Calendar ---
  const renderCalendar = () => {
    const year = viewDate.getFullYear();
    const month = viewDate.getMonth();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const firstDayOfWeek = new Date(year, month, 1).getDay(); // 0 = Sunday
    const today = new Date();
    today.setHours(0,0,0,0);

    const monthLabel = viewDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });

    const days = [];

    // Add empty padding slots for start of month
    for (let i = 0; i < firstDayOfWeek; i++) {
        days.push(<div key={`pad-${i}`} className="aspect-square"></div>);
    }

    // Generate days
    for (let d = 1; d <= daysInMonth; d++) {
        const currentDayDate = new Date(year, month, d);
        const dateStr = getLocalDateString(currentDayDate);

        const isPast = currentDayDate < today;
        let status = 'available';

        if (isPast) {
            status = 'disabled';
        } else {
             // Check existing bookings for this specific date
            const hasBooking = existingBookings.find(b => {
              const bookingDate = new Date(b.start_time);
              const bookingDateStr = getLocalDateString(bookingDate);
              return bookingDateStr === dateStr;
            });

            if (hasBooking) {
              status = hasBooking.status === 'Approved' ? 'booked' : 'pending';
            }
        }

        const isSelected = formData.date === dateStr;

        let colorClass = 'bg-emerald-400/20 hover:bg-emerald-500 hover:text-white text-emerald-900 dark:text-emerald-100 cursor-pointer';

        if (status === 'disabled') colorClass = 'opacity-30 cursor-not-allowed bg-gray-200 dark:bg-gray-800 text-gray-400';
        else if (status === 'booked') colorClass = 'bg-red-400/50 text-red-900 dark:text-red-100 cursor-not-allowed';
        else if (status === 'pending') colorClass = 'bg-yellow-400/50 text-yellow-900 dark:text-yellow-100 cursor-pointer hover:bg-yellow-500 hover:text-white';

        // Highlight selection
        if (isSelected) colorClass = 'bg-blue-600 text-white shadow-lg shadow-blue-500/50 transform scale-105';

        days.push(
            <div 
                key={d}
                onClick={() => {
                    if (status !== 'disabled' && status !== 'booked') {
                        setFormData(prev => ({ ...prev, date: dateStr }));
                    }
                }}
                className={`aspect-square rounded-lg flex items-center justify-center text-xs font-bold transition-all duration-200 ${colorClass}`}
            >
                {d}
            </div>
        );
    }

    return (
      <div className="w-full">
        {/* Month Navigation */}
        <div className="flex justify-between items-center mb-4 px-2">
          <button 
            type="button" 
            onClick={handlePrevMonth} 
            className="p-2 hover:bg-white/20 dark:hover:bg-gray-700 rounded-full transition-colors"
            title="Previous Month"
          >
            <ChevronLeft size={20} className="text-gray-700 dark:text-white" />
          </button>

          <span className="font-bold text-gray-800 dark:text-white text-lg">{monthLabel}</span>

          <button 
            type="button" 
            onClick={handleNextMonth} 
            className="p-2 hover:bg-white/20 dark:hover:bg-gray-700 rounded-full transition-colors"
            title="Next Month"
          >
            <ChevronRight size={20} className="text-gray-700 dark:text-white" />
          </button>
        </div>

        {/* Days Header */}
        <div className="grid grid-cols-7 gap-2 mb-2 text-center">
          {['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(day => (
            <span key={day} className="text-[10px] font-bold text-gray-500 uppercase">{day}</span>
          ))}
        </div>

        {/* Calendar Grid */}
        <div className="grid grid-cols-7 gap-2">
            {days}
        </div>

        <div className="text-center mt-3 pt-3 border-t border-gray-200 dark:border-gray-700/50">
             <button 
                type="button" 
                className="text-xs text-emerald-600 dark:text-emerald-400 cursor-pointer hover:underline" 
                onClick={handleNextMonth}
             >
                Check availability in {new Date(year, month + 1).toLocaleString('default', {month:'long'})} →
             </button>
        </div>
      </div>
    );
  };

  return (
    <div className="pt-28 pb-20 px-4 min-h-screen">
      <div className="max-w-4xl mx-auto">
        <div className="text-center mb-10 print:hidden">
          <h1 className="text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-600 via-emerald-600 to-teal-500 dark:from-emerald-300 dark:to-white mb-4">
            Book Your Experience
          </h1>
          <p className="text-gray-600 dark:text-gray-300">Seamless booking for your perfect event or game.</p>
        </div>

        {step === 3 ? (
          <div className="flex flex-col items-center">
            {/* Action Buttons (Hidden on Print) */}
            <div className="flex gap-4 mb-8 print:hidden">
              <GlassButton onClick={handleDownload} variant="primary">
                <Download size={20} /> Download to Gallery
              </GlassButton>
              <GlassButton onClick={handlePrint} variant="secondary">
                <Printer size={20} /> Print Receipt
              </GlassButton>
              <GlassButton onClick={() => navigate('/')} variant="secondary" className="border-red-200 hover:bg-red-50 text-red-600">
                Close
              </GlassButton>
            </div>

            {/* Receipt Card - This is what gets printed/downloaded */}
            <div id="receipt-card" className="bg-white text-gray-900 w-full max-w-md p-8 rounded-3xl shadow-xl border-t-8 border-emerald-500 relative overflow-hidden">
               {/* Watermark */}
               <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 opacity-5 pointer-events-none">
                 <TreePalm size={300} />
               </div>

               <div className="relative z-10 text-center">
                 <div className="flex items-center justify-center gap-2 mb-2">
                   <div className="bg-emerald-500 p-2 rounded-lg">
                     <TreePalm className="text-white" size={24} />
                   </div>
                   <h2 className="text-2xl font-bold text-emerald-800">JK Palms</h2>
                 </div>
                 <p className="text-xs text-gray-500 uppercase tracking-widest mb-6">Booking Receipt</p>

                 <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100 mb-6">
                   <p className="text-sm text-emerald-600 mb-1">Booking Reference</p>
                   <p className="text-3xl font-mono font-bold text-emerald-700 tracking-wider">{bookingCode}</p>
                 </div>

                 <div className="space-y-4 text-left">
                    <div className="flex justify-between border-b border-dashed border-gray-200 pb-2">
                       <span className="text-gray-500 text-sm">Customer</span>
                       <span className="font-bold">{formData.name}</span>
                    </div>
                    <div className="flex justify-between border-b border-dashed border-gray-200 pb-2">
                       <span className="text-gray-500 text-sm">Venue</span>
                       <span className="font-bold">{formData.venue}</span>
                    </div>
                    <div className="flex justify-between border-b border-dashed border-gray-200 pb-2">
                       <span className="text-gray-500 text-sm">Date</span>
                       <span className="font-bold">{formData.date}</span>
                    </div>
                    {formData.venue === 'Football Pitch' ? (
                      <div className="flex justify-between border-b border-dashed border-gray-200 pb-2">
                         <span className="text-gray-500 text-sm">Time</span>
                         <span className="font-bold">{formData.time} ({formData.duration}hrs)</span>
                      </div>
                    ) : null}
                    <div className="flex justify-between items-center pt-2">
                       <span className="text-gray-500 text-sm">Total Amount</span>
                       <span className="text-xl font-bold text-emerald-600">₦{totalPrice.toLocaleString()}</span>
                    </div>
                 </div>

                 <div className="mt-8 pt-4 border-t border-gray-100">
                    <p className="text-xs text-gray-500 leading-relaxed">
                      Please present this receipt at the entrance to gain access.
                      <br/>Contact: +234 811 886 1619
                    </p>
                 </div>
               </div>
            </div>

            <p className="mt-6 text-sm text-gray-500 dark:text-gray-400 print:hidden">
              Your booking status is currently <strong>Pending</strong>. You can proceed to the venue with this receipt.
            </p>
          </div>
        ) : (
          <div className="grid md:grid-cols-3 gap-8">
            {/* Form Section */}
            <div className="md:col-span-2">
              <GlassCard>
                <form onSubmit={handleSubmit} className="space-y-6">
                  {/* Step 1: Personal Info */}
                  <div className="space-y-4">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-emerald-700 dark:text-emerald-400">
                      <User size={20} /> Contact Details
                    </h3>
                    <div className="grid md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-medium mb-1 text-gray-700 dark:text-gray-300">Full Name</label>
                        <input required type="text" name="name" value={formData.name} onChange={handleInputChange} className="w-full bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="John Doe" />
                      </div>
                      <div>
                        <label className="block text-sm font-medium mb-1 text-gray-700 dark:text-gray-300">Phone</label>
                        <input required type="tel" name="phone" value={formData.phone} onChange={handleInputChange} className="w-full bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="+234..." />
                      </div>
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-1 text-gray-700 dark:text-gray-300">Email</label>
                      <input required type="email" name="email" value={formData.email} onChange={handleInputChange} className="w-full bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="you@example.com" />
                    </div>
                  </div>

                  <div className="border-t border-gray-400/20 my-6"></div>

                  {/* Step 2: Venue Selection */}
                  <div className="space-y-4">
                    <h3 className="text-lg font-bold flex items-center gap-2 text-emerald-700 dark:text-emerald-400">
                      <Calendar size={20} /> Event Details
                    </h3>

                    <div>
                      <label className="block text-sm font-medium mb-2 text-gray-700 dark:text-gray-300">Select Venue</label>
                      <div className="grid grid-cols-2 gap-3">
                        {VENUES.map(v => (
                          <div 
                            key={v.type}
                            onClick={() => setFormData(prev => ({ ...prev, venue: v.type, endDate: '', time: '' }))}
                            className={`cursor-pointer p-4 rounded-xl border transition-all ${
                              formData.venue === v.type 
                              ? 'bg-gradient-to-r from-blue-500 to-emerald-500 text-white border-blue-600 shadow-lg scale-105' 
                              : 'bg-white/40 dark:bg-black/20 border-gray-300 dark:border-gray-700 hover:bg-white/60'
                            }`}
                          >
                            <div className="font-bold text-sm">{v.type}</div>
                            <div className="text-xs opacity-80">₦{v.price.toLocaleString()} {v.unit}</div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="grid md:grid-cols-2 gap-4">
                      <div>
                        <label className="block text-sm font-medium mb-1 text-gray-700 dark:text-gray-300">
                          {formData.venue === 'Football Pitch' ? 'Date' : 'Start Date'}
                        </label>
                        <input 
                          required 
                          type="date" 
                          name="date" 
                          value={formData.date} 
                          onChange={handleInputChange} 
                          className="w-full bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none cursor-pointer" 
                        />
                      </div>

                      {formData.venue === 'Football Pitch' ? (
                        <div>
                          <label className="block text-sm font-medium mb-1 text-gray-700 dark:text-gray-300">Time</label>
                          <input required type="time" name="time" value={formData.time} onChange={handleInputChange} className="w-full bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none" />
                        </div>
                      ) : (
                        <div>
                          <label className="block text-sm font-medium mb-1 text-gray-700 dark:text-gray-300">End Date</label>
                          <input 
                            required 
                            type="date" 
                            name="endDate" 
                            min={formData.date}
                            value={formData.endDate} 
                            onChange={handleInputChange} 
                            className="w-full bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none cursor-pointer" 
                          />
                        </div>
                      )}
                    </div>

                    {formData.venue === 'Football Pitch' && (
                      <div>
                        <label className="block text-sm font-medium mb-2 text-gray-700 dark:text-gray-300">Duration (Hours)</label>
                        <div className="flex gap-2 flex-wrap">
                           {[1, 1.5, 2, 2.5].map(d => (
                             <button
                               key={d}
                               type="button"
                               onClick={() => setFormData(prev => ({ ...prev, duration: d }))}
                               className={`px-4 py-2 rounded-lg text-sm border ${formData.duration === d ? 'bg-emerald-500 text-white border-emerald-600' : 'bg-white/40 dark:bg-black/20 dark:text-gray-300'}`}
                             >
                               {d} hr
                             </button>
                           ))}
                        </div>
                        <p className="text-xs text-orange-500 mt-2 flex items-center gap-1">
                          <AlertCircle size={12}/> Includes 20min buffer between games.
                        </p>
                      </div>
                    )}

                    {formData.venue !== 'Football Pitch' && (
                      <div className="grid grid-cols-2 gap-4">
                        <div className="bg-white/30 dark:bg-black/20 p-3 rounded-lg">
                          <label className="block text-xs font-bold mb-2 uppercase text-gray-500">Adults</label>
                          <input type="number" min="0" value={formData.guests?.adults} onChange={(e) => handleGuestChange('adults', parseInt(e.target.value))} className="w-full bg-transparent border-b border-gray-400 focus:border-emerald-500 outline-none p-1" />
                        </div>
                        <div className="bg-white/30 dark:bg-black/20 p-3 rounded-lg">
                          <label className="block text-xs font-bold mb-2 uppercase text-gray-500">Children</label>
                          <input type="number" min="0" value={formData.guests?.children} onChange={(e) => handleGuestChange('children', parseInt(e.target.value))} className="w-full bg-transparent border-b border-gray-400 focus:border-emerald-500 outline-none p-1" />
                        </div>
                      </div>
                    )}

                    <div>
                      <label className="block text-sm font-medium mb-1 text-gray-700 dark:text-gray-300">Message / Special Requests</label>
                      <textarea name="message" value={formData.message} onChange={handleInputChange} rows={3} className="w-full bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 rounded-lg p-3 focus:ring-2 focus:ring-emerald-500 outline-none"></textarea>
                    </div>
                  </div>

                  {submitError && (
                    <div className="p-4 bg-red-500/20 border border-red-500 text-red-600 dark:text-red-300 rounded-lg text-sm">
                      {submitError}
                    </div>
                  )}

                  <GlassButton type="submit" className="w-full justify-center mt-6" disabled={isSubmitting}>
                    {isSubmitting ? (
                      <span className="flex items-center gap-2">
                        <Loader2 className="animate-spin" /> Checking Availability...
                      </span>
                    ) : (
                      "Confirm & Submit Booking"
                    )}
                  </GlassButton>
                </form>
              </GlassCard>
            </div>

            {/* Summary Sidebar */}
            <div className="md:col-span-1 print:hidden">
               <div className="sticky top-28 space-y-6">
                 {/* Calendar Preview */}
                 <GlassCard className="p-4">
                   <div className="flex justify-between items-center mb-4">
                      <h4 className="text-sm font-bold text-gray-700 dark:text-gray-300">Live Availability</h4>
                      {loadingAvailability && <RefreshCw className="animate-spin text-emerald-500" size={14} />}
                   </div>

                   {renderCalendar()}

                   <div className="flex gap-2 text-[10px] justify-center text-gray-500 mt-4 flex-wrap">
                     <span className="flex items-center gap-1"><div className="w-2 h-2 bg-emerald-400 rounded-full"></div>Avail</span>
                     <span className="flex items-center gap-1"><div className="w-2 h-2 bg-yellow-400 rounded-full"></div>Pending</span>
                     <span className="flex items-center gap-1"><div className="w-2 h-2 bg-red-400 rounded-full"></div>Booked</span>
                   </div>

                 </GlassCard>

                 {/* Price Summary */}
                 <GlassCard className="bg-emerald-900/10 dark:bg-emerald-500/10 border-emerald-500/30">
                   <h3 className="text-lg font-bold mb-4 border-b border-emerald-500/20 pb-2">Booking Summary</h3>
                   <div className="space-y-3 text-sm text-gray-700 dark:text-gray-300">
                     <div className="flex justify-between">
                       <span>Venue</span>
                       <span className="font-bold">{formData.venue}</span>
                     </div>
                     <div className="flex justify-between">
                       <span>{formData.venue === 'Football Pitch' ? 'Date' : 'Start Date'}</span>
                       <span>{formData.date || 'Not selected'}</span>
                     </div>
                     {formData.venue !== 'Football Pitch' && formData.endDate && (
                       <div className="flex justify-between">
                         <span>End Date</span>
                         <span>{formData.endDate}</span>
                       </div>
                     )}
                     {formData.venue === 'Football Pitch' && (
                       <div className="flex justify-between">
                         <span>Duration</span>
                         <span>{formData.duration} hrs</span>
                       </div>
                     )}
                     <div className="border-t border-emerald-500/20 pt-3 flex justify-between items-center">
                       <span className="font-bold">Total Estimated</span>
                       <span className="text-2xl font-bold text-emerald-600 dark:text-emerald-400">₦{totalPrice.toLocaleString()}</span>
                     </div>
                   </div>
                 </GlassCard>
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Booking;

import React, { useState, useEffect, useRef } from 'react';
import { GlassCard, GlassButton } from './GlassUI';
import { useData } from '../context/DataContext';
import { Lock, LogOut, Check, X, Edit2, Trash2, Image as ImageIcon, RefreshCw, Loader2, Upload, Plus } from 'lucide-react';
import { BookingRecord } from '../types';
import { supabase } from '../lib/supabase';

const AdminPanel: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [activeTab, setActiveTab] = useState<'bookings' | 'features' | 'gallery' | 'content'>('bookings');

  // Using any[] to accommodate the extra 'row_id' property mapping without changing global types
  const [dbBookings, setDbBookings] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const loginRef = useRef<HTMLDivElement>(null);

  // Upload State
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadTarget, setUploadTarget] = useState<{type: 'feature' | 'gallery' | 'hero' | 'testimonial', index?: number} | null>(null);
  const [isUploading, setIsUploading] = useState(false);

  const { 
    features, updateFeature, 
    galleryImages, updateGallery,
    heroImage, updateHeroImage,
    testimonials, updateTestimonials
  } = useData();

  // Scroll handling
  useEffect(() => {
    if (!isAuthenticated) {
      setTimeout(() => {
        loginRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 100);
    } else {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [isAuthenticated]);

  const fetchBookings = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('bookings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;

      const mappedData = data ? data.map((b: any) => ({
        ...b,
        id: b.booking_code || b.id, // Display ID (Booking Code)
        row_id: b.id, // Actual Database Primary Key
        venue: b.venue,
        date: b.start_time ? new Date(b.start_time).toLocaleDateString() : 'N/A',
        time: b.start_time ? new Date(b.start_time).toLocaleTimeString() : 'N/A',
        totalPrice: b.price ? parseFloat(b.price) : 0
      })) : [];

      setDbBookings(mappedData);
    } catch (error: any) {
      console.error("Failed to fetch bookings", error);
      if (error.message && error.message.includes("apikey")) {
         alert("Supabase API Key not configured in lib/supabase.ts");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateStatus = async (rowId: any, status: 'Approved' | 'Rejected') => {
    try {
      // Use Primary Key for updates
      const { error } = await supabase
        .from('bookings')
        .update({ status: status })
        .eq('id', rowId);

      if (error) throw error;

      // Removed Email sending logic here as requested

      fetchBookings();
    } catch (e: any) {
      console.error("Update failed:", e);
      alert("Failed to update status: " + (e.message || JSON.stringify(e)));
    }
  };

  const handleDeleteBooking = async (rowId: any, displayId: string) => {
    if (!window.confirm(`Are you sure you want to permanently delete booking ${displayId}?`)) return;

    try {
      console.log("Deleting booking row:", rowId);

      // Use exact count to detect RLS silent failures
      const { error, count } = await supabase
        .from('bookings')
        .delete({ count: 'exact' })
        .eq('id', rowId);

      if (error) throw error;

      // If no rows were deleted, it's likely an RLS permission issue
      if (count === 0) {
        alert("Request sent, but no records were deleted.\n\nPossible Cause: Row Level Security (RLS) policies on Supabase are preventing deletion.\n\nSolution: Go to Supabase Dashboard > Table Editor > 'bookings' > Policies, and ensure the 'anon' or 'public' role has DELETE permissions.");
        return;
      }

      // Update local state to remove the deleted item
      setDbBookings(prev => prev.filter(b => b.row_id !== rowId));

    } catch (e: any) {
      console.error("Delete failed:", e);
      const msg = e.message || JSON.stringify(e);
      alert(`Failed to delete: ${msg}`);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === 'admin' && password === 'admin123') {
      setIsAuthenticated(true);
      fetchBookings();
    } else {
      alert('Invalid Credentials (try admin/admin123)');
    }
  };

  // --- Image Upload Logic ---
  const triggerUpload = (type: 'feature' | 'gallery' | 'hero' | 'testimonial', index?: number) => {
    setUploadTarget({ type, index });
    fileInputRef.current?.click();
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;

    const file = e.target.files[0];
    setIsUploading(true);

    try {
      // Create a unique file name
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(2)}.${fileExt}`;
      const filePath = `${fileName}`;

      // Upload to 'images' bucket
      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file);

      if (uploadError) {
        if (uploadError.message.includes("Bucket not found")) {
          throw new Error("Bucket 'images' not found. Please create a public bucket named 'images' in your Supabase Dashboard.");
        }
        throw uploadError;
      }

      // Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('images')
        .getPublicUrl(filePath);

      // Update State based on target
      if (uploadTarget?.type === 'feature' && typeof uploadTarget.index === 'number') {
         const feature = features[uploadTarget.index];
         updateFeature(uploadTarget.index, { ...feature, image: publicUrl });
      } else if (uploadTarget?.type === 'gallery') {
         updateGallery([...galleryImages, publicUrl]);
      } else if (uploadTarget?.type === 'hero') {
         updateHeroImage(publicUrl);
      } else if (uploadTarget?.type === 'testimonial' && typeof uploadTarget.index === 'number') {
         const newTestimonials = [...testimonials];
         newTestimonials[uploadTarget.index] = { ...newTestimonials[uploadTarget.index], avatar: publicUrl };
         updateTestimonials(newTestimonials);
      }

      alert("Image uploaded successfully!");
    } catch (error: any) {
      console.error('Upload failed:', error);

      // Handle RLS Errors specifically to guide the user
      if (error.message && (error.message.includes('row-level security') || error.message.includes('permission denied'))) {
        alert(
          "UPLOAD FAILED: Permission Denied\n\n" +
          "This is a security setting in your Supabase project.\n\n" +
          "HOW TO FIX:\n" +
          "1. Go to Supabase Dashboard > Storage > 'images' bucket.\n" +
          "2. Click the 'Policies' tab (or Configuration).\n" +
          "3. Create a new policy for 'INSERT' (Upload) permissions.\n" +
          "4. Allow access for 'anon' or 'public' users.\n" +
          "5. Save policy and try again."
        );
      } else {
        alert(`Upload failed: ${error.message}`);
      }
    } finally {
      setIsUploading(false);
      setUploadTarget(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleTestimonialChange = (index: number, field: string, value: string) => {
    const newTestimonials = [...testimonials];
    newTestimonials[index] = { ...newTestimonials[index], [field]: value };
    updateTestimonials(newTestimonials);
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen pt-24 px-4 flex items-center justify-center">
        <div ref={loginRef} className="w-full max-w-md">
          <GlassCard className="p-8 text-center">
            <div className="bg-emerald-500/20 p-4 rounded-full w-20 h-20 mx-auto flex items-center justify-center mb-6">
              <Lock className="text-emerald-600 w-10 h-10" />
            </div>
            <h2 className="text-2xl font-bold mb-6 text-gray-800 dark:text-white">Admin Access</h2>
            <form onSubmit={handleLogin} className="space-y-4">
              <input
                type="text"
                placeholder="Username"
                value={username}
                onChange={e => setUsername(e.target.value)}
                className="w-full p-3 rounded-xl bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                className="w-full p-3 rounded-xl bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <GlassButton type="submit" className="w-full justify-center">Login</GlassButton>
            </form>
          </GlassCard>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pt-24 px-4 pb-10">
      <div className="max-w-7xl mx-auto">
        {/* Hidden File Input */}
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/*" 
          onChange={handleFileSelect} 
        />

        {/* Header */}
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold text-gray-800 dark:text-white">Admin Dashboard</h1>
          <button 
            onClick={() => setIsAuthenticated(false)}
            className="flex items-center gap-2 text-red-500 hover:text-red-600 font-medium"
          >
            <LogOut size={18} /> Logout
          </button>
        </div>

        {/* Tabs */}
        <div className="flex gap-4 mb-8 overflow-x-auto pb-2">
          {['bookings', 'features', 'gallery', 'content'].map(tab => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`px-6 py-2 rounded-full font-bold capitalize transition-all ${
                activeTab === tab 
                ? 'bg-emerald-500 text-white shadow-lg' 
                : 'bg-white/20 text-gray-600 dark:text-gray-300 hover:bg-white/40'
              }`}
            >
              {tab}
            </button>
          ))}
        </div>

        {/* Content Area */}
        <GlassCard className="min-h-[500px]">
          {isUploading && (
            <div className="absolute inset-0 z-50 bg-black/50 backdrop-blur-sm flex flex-col items-center justify-center rounded-2xl">
              <Loader2 className="animate-spin text-white w-12 h-12 mb-4" />
              <div className="text-white font-bold">Uploading Image...</div>
            </div>
          )}

          {activeTab === 'bookings' && (
            <div className="overflow-x-auto">
              <div className="flex justify-between items-center mb-4 px-4">
                <h3 className="font-bold text-lg text-emerald-600">Supabase Records</h3>
                <button onClick={fetchBookings} className="p-2 bg-emerald-500/10 rounded-full hover:bg-emerald-500/30 text-emerald-600 transition-colors">
                  <RefreshCw size={20} className={isLoading ? "animate-spin" : ""} />
                </button>
              </div>

              {isLoading ? (
                <div className="flex justify-center p-12">
                   <Loader2 className="animate-spin text-emerald-500" size={40} />
                </div>
              ) : (
                <table className="w-full text-left border-collapse min-w-[800px]">
                  <thead>
                    <tr className="border-b border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400">
                      <th className="p-4">Code</th>
                      <th className="p-4">Customer</th>
                      <th className="p-4">Venue</th>
                      <th className="p-4">Date/Time</th>
                      <th className="p-4">Total</th>
                      <th className="p-4">Status</th>
                      <th className="p-4">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="text-gray-700 dark:text-gray-300">
                    {dbBookings.length === 0 ? (
                      <tr>
                        <td colSpan={7} className="p-8 text-center opacity-50">No bookings found in database.</td>
                      </tr>
                    ) : (
                      dbBookings.map(booking => (
                        <tr key={booking.row_id} className="border-b border-gray-100 dark:border-gray-800 hover:bg-white/10">
                          <td className="p-4 font-mono text-xs">{booking.id}</td>
                          <td className="p-4">
                            <div className="font-bold">{booking.name}</div>
                            <div className="text-xs opacity-70">{booking.email}</div>
                            <div className="text-xs opacity-70">{booking.phone}</div>
                          </td>
                          <td className="p-4">{booking.venue}</td>
                          <td className="p-4">
                            <div>{booking.date}</div>
                            <div className="text-xs text-emerald-500">{booking.time}</div>
                          </td>
                          <td className="p-4 font-bold">₦{booking.totalPrice?.toLocaleString()}</td>
                          <td className="p-4">
                            <span className={`px-2 py-1 rounded-full text-xs font-bold ${
                              booking.status === 'Approved' ? 'bg-green-100 text-green-700' :
                              booking.status === 'Rejected' ? 'bg-red-100 text-red-700' :
                              'bg-yellow-100 text-yellow-700'
                            }`}>
                              {booking.status}
                            </span>
                          </td>
                          <td className="p-4 flex gap-2">
                            {booking.status === 'Pending' && (
                              <>
                                <button 
                                  onClick={() => handleUpdateStatus(booking.row_id, 'Approved')}
                                  title="Approve"
                                  className="p-2 bg-green-500/20 text-green-600 rounded-lg hover:bg-green-500 hover:text-white transition-colors"
                                >
                                  <Check size={18} />
                                </button>
                                <button 
                                  onClick={() => handleUpdateStatus(booking.row_id, 'Rejected')}
                                  title="Reject"
                                  className="p-2 bg-red-500/20 text-red-600 rounded-lg hover:bg-red-500 hover:text-white transition-colors"
                                >
                                  <X size={18} />
                                </button>
                              </>
                            )}
                            <button 
                              onClick={() => handleDeleteBooking(booking.row_id, booking.id)}
                              title="Delete Booking"
                              className="p-2 bg-gray-500/10 text-gray-500 rounded-lg hover:bg-red-500 hover:text-white transition-colors"
                            >
                              <Trash2 size={18} />
                            </button>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              )}
            </div>
          )}

          {activeTab === 'features' && (
            <div className="grid md:grid-cols-2 gap-6">
              {features.map((feature, idx) => (
                <div key={idx} className="bg-white/30 dark:bg-black/20 p-4 rounded-xl border border-white/10">
                   <div className="mb-4 relative h-40 rounded-lg overflow-hidden group">
                     <img src={feature.image} alt={feature.title} className="w-full h-full object-cover" />
                     <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                       <button 
                         className="bg-emerald-500 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-emerald-600"
                         onClick={() => triggerUpload('feature', idx)}
                       >
                         <Upload size={16} /> Upload New
                       </button>
                     </div>
                   </div>
                   <input 
                     value={feature.title} 
                     onChange={(e) => updateFeature(idx, { ...feature, title: e.target.value })}
                     className="w-full bg-transparent font-bold text-lg mb-2 border-b border-transparent focus:border-emerald-500 outline-none text-gray-800 dark:text-white"
                   />
                   <textarea 
                     value={feature.description}
                     onChange={(e) => updateFeature(idx, { ...feature, description: e.target.value })}
                     className="w-full bg-transparent text-sm text-gray-600 dark:text-gray-300 resize-none h-20 border border-transparent focus:border-emerald-500 rounded p-1 outline-none"
                   />
                </div>
              ))}
            </div>
          )}

          {activeTab === 'gallery' && (
             <div>
               <div className="mb-6 flex gap-3">
                 <button 
                   onClick={() => triggerUpload('gallery')}
                   className="bg-emerald-500 text-white px-6 py-3 rounded-xl font-bold hover:bg-emerald-600 flex items-center gap-2 shadow-lg"
                 >
                   <Upload size={20} /> Upload Photo
                 </button>

                 <button 
                   onClick={() => {
                      const url = prompt("Enter Image URL:");
                      if (url) updateGallery([...galleryImages, url]);
                   }}
                   className="bg-white/10 text-gray-700 dark:text-white border border-gray-500/30 px-4 py-3 rounded-xl font-bold hover:bg-white/20 flex items-center gap-2"
                 >
                   <Plus size={20} /> Add URL
                 </button>
               </div>

               <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                 {galleryImages.map((image, idx) => (
                   <div key={idx} className="relative group rounded-xl overflow-hidden h-40 shadow-md">
                     <img src={image} className="w-full h-full object-cover transition-transform group-hover:scale-110" alt="" />
                     <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                       <button 
                          onClick={() => {
                            if (window.confirm("Remove this image?")) {
                              updateGallery(galleryImages.filter((_, i) => i !== idx));
                            }
                          }}
                          className="bg-red-500 text-white p-2 rounded-full hover:bg-red-600"
                       >
                         <Trash2 size={20} />
                       </button>
                     </div>
                   </div>
                 ))}
               </div>
             </div>
          )}

          {activeTab === 'content' && (
            <div className="space-y-12">
              {/* Hero Image Section */}
              <section>
                <h3 className="text-2xl font-bold mb-6 text-gray-800 dark:text-white flex items-center gap-2">
                  <ImageIcon className="text-emerald-500" /> Hero Section Image
                </h3>
                <div className="bg-white/30 dark:bg-black/20 p-6 rounded-2xl border border-white/10">
                  <div className="relative h-64 md:h-80 w-full rounded-xl overflow-hidden group">
                    <img 
                      src={heroImage} 
                      alt="Hero Banner" 
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => triggerUpload('hero')}
                        className="bg-emerald-500 text-white px-6 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-emerald-600 shadow-lg transform hover:scale-105 transition-all"
                      >
                        <Upload size={20} /> Upload New Banner
                      </button>
                    </div>
                  </div>
                  <p className="mt-4 text-sm text-gray-500 dark:text-gray-400 text-center">
                    This image appears as the large banner on the Home page. Recommended size: 1920x1080.
                  </p>
                </div>
              </section>

              {/* Testimonials Section */}
              <section>
                <h3 className="text-2xl font-bold mb-6 text-gray-800 dark:text-white flex items-center gap-2">
                  <Edit2 className="text-emerald-500" /> Client Reviews
                </h3>
                <div className="grid md:grid-cols-3 gap-6">
                  {testimonials.map((testimonial, idx) => (
                    <div key={idx} className="bg-white/30 dark:bg-black/20 p-6 rounded-2xl border border-white/10 relative">
                      <div className="flex justify-center mb-4">
                        <div className="relative w-24 h-24 group">
                          <img 
                            src={testimonial.avatar} 
                            alt="Client" 
                            className="w-full h-full rounded-full object-cover border-4 border-emerald-500/20"
                          />
                          <button 
                            onClick={() => triggerUpload('testimonial', idx)}
                            className="absolute inset-0 flex items-center justify-center bg-black/50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity text-white"
                          >
                            <Upload size={18} />
                          </button>
                        </div>
                      </div>

                      <div className="space-y-3">
                         <div>
                           <label className="text-xs font-bold text-gray-500 uppercase">Name</label>
                           <input 
                             type="text" 
                             value={testimonial.name}
                             onChange={(e) => handleTestimonialChange(idx, 'name', e.target.value)}
                             className="w-full bg-transparent border-b border-gray-400 focus:border-emerald-500 outline-none py-1 font-bold text-gray-800 dark:text-white"
                           />
                         </div>
                         <div>
                           <label className="text-xs font-bold text-gray-500 uppercase">Role</label>
                           <input 
                             type="text" 
                             value={testimonial.role}
                             onChange={(e) => handleTestimonialChange(idx, 'role', e.target.value)}
                             className="w-full bg-transparent border-b border-gray-400 focus:border-emerald-500 outline-none py-1 text-sm text-emerald-600"
                           />
                         </div>
                         <div>
                           <label className="text-xs font-bold text-gray-500 uppercase">Comment</label>
                           <textarea 
                             rows={3}
                             value={testimonial.comment}
                             onChange={(e) => handleTestimonialChange(idx, 'comment', e.target.value)}
                             className="w-full bg-transparent border border-gray-400/30 rounded p-2 focus:border-emerald-500 outline-none text-sm text-gray-600 dark:text-gray-300 mt-1 resize-none"
                           />
                         </div>
                      </div>
                    </div>
                  ))}
                </div>
              </section>
            </div>
          )}
        </GlassCard>
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { BookingRecord, FeatureItem, ServiceItem, Testimonial } from '../types';
import { INITIAL_FEATURES, INITIAL_SERVICES, INITIAL_GALLERY_IMAGES, TESTIMONIALS } from '../constants';

interface DataContextType {
  features: FeatureItem[];
  services: ServiceItem[];
  galleryImages: string[];
  bookings: BookingRecord[];
  heroImage: string;
  testimonials: Testimonial[];
  logo: string;
  addBooking: (booking: BookingRecord) => void;
  updateBookingStatus: (id: string, status: 'Pending' | 'Approved' | 'Rejected') => void;
  updateFeature: (index: number, feature: FeatureItem) => void;
  updateService: (index: number, service: ServiceItem) => void;
  updateGallery: (images: string[]) => void;
  updateHeroImage: (url: string) => void;
  updateTestimonials: (testimonials: Testimonial[]) => void;
  updateLogo: (url: string) => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Load initial state from LocalStorage or use Constants
  const [features, setFeatures] = useState<FeatureItem[]>(() => {
    const saved = localStorage.getItem('jk_features');
    return saved ? JSON.parse(saved) : INITIAL_FEATURES;
  });

  const [services, setServices] = useState<ServiceItem[]>(() => {
    const saved = localStorage.getItem('jk_services');
    return saved ? JSON.parse(saved) : INITIAL_SERVICES;
  });

  const [galleryImages, setGalleryImages] = useState<string[]>(() => {
    const saved = localStorage.getItem('jk_gallery_images');
    return saved ? JSON.parse(saved) : INITIAL_GALLERY_IMAGES;
  });

  const [bookings, setBookings] = useState<BookingRecord[]>(() => {
    const saved = localStorage.getItem('jk_bookings');
    return saved ? JSON.parse(saved) : [];
  });

  const [heroImage, setHeroImage] = useState<string>(() => {
    return localStorage.getItem('jk_hero_image') || "./img/captured3.jpg";
  });

  const [testimonials, setTestimonials] = useState<Testimonial[]>(() => {
    const saved = localStorage.getItem('jk_testimonials');
    return saved ? JSON.parse(saved) : TESTIMONIALS;
  });

  const [logo, setLogo] = useState<string>(() => {
    return localStorage.getItem('jk_logo') || "";
  });

  // Persist to LocalStorage whenever state changes
  useEffect(() => localStorage.setItem('jk_features', JSON.stringify(features)), [features]);
  useEffect(() => localStorage.setItem('jk_services', JSON.stringify(services)), [services]);
  useEffect(() => localStorage.setItem('jk_gallery_images', JSON.stringify(galleryImages)), [galleryImages]);
  useEffect(() => localStorage.setItem('jk_bookings', JSON.stringify(bookings)), [bookings]);
  useEffect(() => localStorage.setItem('jk_hero_image', heroImage), [heroImage]);
  useEffect(() => localStorage.setItem('jk_testimonials', JSON.stringify(testimonials)), [testimonials]);
  useEffect(() => localStorage.setItem('jk_logo', logo), [logo]);

  // Update Favicon dynamically when logo changes
  useEffect(() => {
    if (logo) {
      let link = document.querySelector("link[rel~='icon']") as HTMLLinkElement;
      if (!link) {
        link = document.createElement('link');
        link.rel = 'icon';
        document.head.appendChild(link);
      }
      link.href = logo;
    }
  }, [logo]);

  const addBooking = (booking: BookingRecord) => {
    setBookings(prev => [booking, ...prev]);
  };

  const updateBookingStatus = (id: string, status: 'Pending' | 'Approved' | 'Rejected') => {
    setBookings(prev => prev.map(b => b.id === id ? { ...b, status } : b));
  };

  const updateFeature = (index: number, feature: FeatureItem) => {
    const newFeatures = [...features];
    newFeatures[index] = feature;
    setFeatures(newFeatures);
  };

  const updateService = (index: number, service: ServiceItem) => {
    const newServices = [...services];
    newServices[index] = service;
    setServices(newServices);
  };

  const updateGallery = (images: string[]) => {
    setGalleryImages(images);
  };

  const updateHeroImage = (url: string) => {
    setHeroImage(url);
  };

  const updateTestimonials = (newTestimonials: Testimonial[]) => {
    setTestimonials(newTestimonials);
  };

  const updateLogo = (url: string) => {
    setLogo(url);
  };

  return (
    <DataContext.Provider value={{
      features,
      services,
      galleryImages,
      bookings,
      heroImage,
      testimonials,
      logo,
      addBooking,
      updateBookingStatus,
      updateFeature,
      updateService,
      updateGallery,
      updateHeroImage,
      updateTestimonials,
      updateLogo
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error("useData must be used within a DataProvider");
  return context;
};

import React, { useState, useEffect, useRef } from 'react';
import { GlassCard, GlassButton } from './GlassUI';
import { useData } from '../context/DataContext';
import { Lock, LogOut, Check, X, Edit2, Trash2, Image as ImageIcon, RefreshCw, Loader2, Upload, Plus, Citrus } from 'lucide-react';
import { BookingRecord } from '../types';
import { supabase } from '../lib/supabase';

const AdminPanel: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [activeTab, setActiveTab] = useState<'bookings' | 'features' | 'gallery' | 'content'>('bookings');

  // Using any[] to accommodate the extra 'row_id' property mapping without changing global types
  const [dbBookings, setDbBookings] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const loginRef = useRef<HTMLDivElement>(null);

  // Upload State
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadTarget, setUploadTarget] = useState<{type: 'feature' | 'gallery' | 'hero' | 'testimonial' | 'logo', index?: number} | null>(null);
  const [isUploading, setIsUploading] = useState(false);

  const { 
    features, updateFeature, 
    galleryImages, updateGallery,
    heroImage, updateHeroImage,
    testimonials, updateTestimonials,
    logo, updateLogo
  } = useData();

  // Scroll handling
  useEffect(() => {
    if (!isAuthenticated) {
      setTimeout(() => {
        loginRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 100);
    } else {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [isAuthenticated]);

  const fetchBookings = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('bookings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;

      const mappedData = data ? data.map((b: any) => ({
        ...b,
        id: b.booking_code || b.id, // Display ID (Booking Code)
        row_id: b.id, // Actual Database Primary Key
        venue: b.venue,
        date: b.start_time ? new Date(b.start_time).toLocaleDateString() : 'N/A',
        time: b.start_time ? new Date(b.start_time).toLocaleTimeString() : 'N/A',
        totalPrice: b.price ? parseFloat(b.price) : 0
      })) : [];

      setDbBookings(mappedData);
    } catch (error: any) {
      console.error("Failed to fetch bookings", error);
      if (error.message && error.message.includes("apikey")) {
         alert("Supabase API Key not configured in lib/supabase.ts");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateStatus = async (rowId: any, status: 'Approved' | 'Rejected') => {
    try {
      // Use Primary Key for updates
      const { error } = await supabase
        .from('bookings')
        .update({ status: status })
        .eq('id', rowId);

      if (error) throw error;

      // Removed Email sending logic here as requested

      fetchBookings();
    } catch (e: any) {
      console.error("Update failed:", e);
      alert("Failed to update status: " + (e.message || JSON.stringify(e)));
    }
  };

  const handleDeleteBooking = async (rowId: any, displayId: string) => {
    if (!window.confirm(`Are you sure you want to permanently delete booking ${displayId}?`)) return;

    try {
      console.log("Deleting booking row:", rowId);

      // Use exact count to detect RLS silent failures
      const { error, count } = await supabase
        .from('bookings')
        .delete({ count: 'exact' })
        .eq('id', rowId);

      if (error) throw error;

      // If no rows were deleted, it's likely an RLS permission issue
      if (count === 0) {
        alert("Request sent, but no records were deleted.\n\nPossible Cause: Row Level Security (RLS) policies on Supabase are preventing deletion.\n\nSolution: Go to Supabase Dashboard > Table Editor > 'bookings' > Policies, and ensure the 'anon' or 'public' role has DELETE permissions.");
        return;
      }

      // Update local state to remove the deleted item
      setDbBookings(prev => prev.filter(b => b.row_id !== rowId));

    } catch (e: any) {
      console.error("Delete failed:", e);
      const msg = e.message || JSON.stringify(e);
      alert(`Failed to delete: ${msg}`);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === 'admin' && password === 'admin123') {
      setIsAuthenticated(true);
      fetchBookings();
    } else {
      alert('Invalid Credentials (try admin/admin123)');
    }
  };

  // --- Image Upload Logic ---
  const triggerUpload = (type: 'feature' | 'gallery' | 'hero' | 'testimonial' | 'logo', index?: number) => {
    setUploadTarget({ type, index });
    fileInputRef.current?.click();
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;

    const file = e.target.files[0];
    setIsUploading(true);

    try {
      // Create a unique file name
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(2)}.${fileExt}`;
      const filePath = `${fileName}`;

      // Upload to 'images' bucket
      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file);

      if (uploadError) {
        if (uploadError.message.includes("Bucket not found")) {
          throw new Error("Bucket 'images' not found. Please create a public bucket named 'images' in your Supabase Dashboard.");
        }
        throw uploadError;
      }

      // Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('images')
        .getPublicUrl(filePath);

      // Update State based on target
      if (uploadTarget?.type === 'feature' && typeof uploadTarget.index === 'number') {
         const feature = features[uploadTarget.index];
         updateFeature(uploadTarget.index, { ...feature, image: publicUrl });
      } else if (uploadTarget?.type === 'gallery') {
         updateGallery([...galleryImages, publicUrl]);
      } else if (uploadTarget?.type === 'hero') {
         updateHeroImage(publicUrl);
      } else if (uploadTarget?.type === 'logo') {
         updateLogo(publicUrl);
      } else if (uploadTarget?.type === 'testimonial' && typeof uploadTarget.index === 'number') {
         const newTestimonials = [...testimonials];
         newTestimonials[uploadTarget.index] = { ...newTestimonials[uploadTarget.index], avatar: publicUrl };
         updateTestimonials(newTestimonials);
      }

      alert("Image uploaded successfully!");
    } catch (error: any) {
      console.error('Upload failed:', error);

      // Handle RLS Errors specifically to guide the user
      if (error.message && (error.message.includes('row-level security') || error.message.includes('permission denied'))) {
        alert(
          "UPLOAD FAILED: Permission Denied\n\n" +
          "This is a security setting in your Supabase project.\n\n" +
          "HOW TO FIX:\n" +
          "1. Go to Supabase Dashboard > Storage > 'images' bucket.\n" +
          "2. Click the 'Policies' tab (or Configuration).\n" +
          "3. Create a new policy for 'INSERT' (Upload) permissions.\n" +
          "4. Allow access for 'anon' or 'public' users.\n" +
          "5. Save policy and try again."
        );
      } else {
        alert(`Upload failed: ${error.message}`);
      }
    } finally {
      setIsUploading(false);
      setUploadTarget(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleTestimonialChange = (index: number, field: string, value: string) => {
    const newTestimonials = [...testimonials];
    newTestimonials[index] = { ...newTestimonials[index], [field]: value };
    updateTestimonials(newTestimonials);
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen pt-24 px-4 flex items-center justify-center">
        <div ref={loginRef} className="w-full max-w-md">
          <GlassCard className="p-8 text-center">
            <div className="bg-emerald-500/20 p-4 rounded-full w-20 h-20 mx-auto flex items-center justify-center mb-6">
              <Lock className="text-emerald-600 w-10 h-10" />
            </div>
            <h2 className="text-2xl font-bold mb-6 text-gray-800 dark:text-white">Admin Access</h2>
            <form onSubmit={handleLogin} className="space-y-4">
              <input
                type="text"
                placeholder="Username"
                value={username}
                onChange={e => setUsername(e.target.value)}
                className="w-full p-3 rounded-xl bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                className="w-full p-3 rounded-xl bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <GlassButton type="submit" className="w-full justify-center">Login</GlassButton>
            </form>
          </GlassCard>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pt-24 px-4 pb-10">
      <div className="max-w-7xl mx-auto">
        {/* Hidden File Input */}
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept="image/*" 
          onChange={handleFileSelect} 
        />

        {/* Header */}
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold text-gray-800 dark:text-white">Admin Dashboard</h1>
          <button 
            onClick={() => setIsAuthenticated(false)}
            className="flex items-center gap-2 text-red-500 hover:text-red-600 font-medium"
          >
            <LogOut size={18} /> Logout
          </button>
        </div>

        {/* Tabs */}
        <div className="flex gap-4 mb-8 overflow-x-auto pb-2">
          {['bookings', 'features', 'gallery', 'content'].map(tab => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`px-6 py-2 rounded-full font-bold capitalize transition-all ${
                activeTab === tab 
