        break;
      case 'jk_events': 
        setEvents(val); 
        localStorage.setItem('jk_events', JSON.stringify(val));
        break;
    }
  };

  // --- Real-time Sync with Supabase ---
  useEffect(() => {
    const fetchGlobalContent = async () => {
      try {
        const { data, error } = await supabase.from('site_content').select('key, value');
        if (error) {
          console.warn("Could not fetch global content (Check RLS policies):", error.message);
          return;
        }

        if (data) {
          data.forEach(item => {
            updateStateFromKey(item.key, item.value);
          });
        }
      } catch (err) {
