    const channel = supabase.channel('content_updates')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'site_content' }, async (payload) => {
         // We fetch the row explicitly to ensure we get the full JSON value 
         // (Payloads can sometimes be truncated or miss TOAST columns)
