         if (!record || !record.key) return;

         const { data } = await supabase.from('site_content').select('value').eq('key', record.key).single();
         if (data) {
            updateStateFromKey(record.key, data.value);
         }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  // Update Favicon dynamically when logo changes
