import React, { createContext, useContext, useState, useEffect, useRef, useCallback } from 'react';
import { BookingRecord, FeatureItem, ServiceItem, Testimonial, EventItem } from '../types';
import { INITIAL_FEATURES, INITIAL_SERVICES, INITIAL_GALLERY_IMAGES, TESTIMONIALS, INITIAL_EVENTS } from '../constants';
import { supabase } from '../lib/supabase';

interface DataContextType {
  features: FeatureItem[];
  services: ServiceItem[];
  galleryImages: string[];
  bookings: BookingRecord[];
  heroImage: string;
  testimonials: Testimonial[];
  logo: string;
  events: EventItem[];
  syncStatus: 'synced' | 'saving' | 'error';
  syncError: string | null;
  addBooking: (booking: BookingRecord) => void;
  updateBookingStatus: (id: string, status: 'Pending' | 'Approved' | 'Rejected') => void;
  updateFeature: (index: number, feature: FeatureItem) => void;
  updateService: (index: number, service: ServiceItem) => void;
  updateGallery: (images: string[]) => void;
  updateHeroImage: (url: string) => void;
  updateTestimonials: (testimonials: Testimonial[]) => void;
  updateLogo: (url: string) => void;
  updateEvents: (events: EventItem[]) => void;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

export const DataProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Load initial state from LocalStorage or use Constants (Optimistic Initial State)
  const [features, setFeatures] = useState<FeatureItem[]>(() => {
    const saved = localStorage.getItem('jk_features');
    return saved ? JSON.parse(saved) : INITIAL_FEATURES;
  });

  const [services, setServices] = useState<ServiceItem[]>(() => {
    const saved = localStorage.getItem('jk_services');
    return saved ? JSON.parse(saved) : INITIAL_SERVICES;
  });

  const [galleryImages, setGalleryImages] = useState<string[]>(() => {
    const saved = localStorage.getItem('jk_gallery_images');
    return saved ? JSON.parse(saved) : INITIAL_GALLERY_IMAGES;
  });

  // Bookings in Context are for local user history mainly. Admin fetches from DB directly.
  const [bookings, setBookings] = useState<BookingRecord[]>(() => {
    const saved = localStorage.getItem('jk_bookings');
    return saved ? JSON.parse(saved) : [];
  });

  const [heroImage, setHeroImage] = useState<string>(() => {
    return localStorage.getItem('jk_hero_image') || "https://jkpalmandgarden.com/img/captured3.jpg";
  });

  const [testimonials, setTestimonials] = useState<Testimonial[]>(() => {
    const saved = localStorage.getItem('jk_testimonials');
    return saved ? JSON.parse(saved) : TESTIMONIALS;
  });

  const [logo, setLogo] = useState<string>(() => {
    return localStorage.getItem('jk_logo') || "";
  });

  const [events, setEvents] = useState<EventItem[]>(() => {
    const saved = localStorage.getItem('jk_events');
    return saved ? JSON.parse(saved) : INITIAL_EVENTS;
  });

  const [syncStatus, setSyncStatus] = useState<'synced' | 'saving' | 'error'>('synced');
  const [syncError, setSyncError] = useState<string | null>(null);

  // Ref to store debounce timers
  const saveTimeouts = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  // Persist to LocalStorage (Immediate) AND Supabase (Debounced or Immediate)
  const persist = async (key: string, value: any, immediate = false) => {
    // 1. Save to LocalStorage immediately
    localStorage.setItem(key, typeof value === 'string' ? value : JSON.stringify(value));
    setSyncStatus('saving');
    setSyncError(null);

    const saveToDb = async () => {
      try {
        // Use 'content' column instead of 'value'
        const { error } = await supabase.from('site_content').upsert({ key, content: value });
        if (error) throw error;
        setSyncStatus('synced');
      } catch (err: any) {
        console.error(`Failed to sync ${key} to cloud:`, err);
        setSyncStatus('error');
        setSyncError(err.message || "Unknown database error");
      }
    };

    // Clear existing timeout for this key
    if (saveTimeouts.current[key]) {
      clearTimeout(saveTimeouts.current[key]);
      delete saveTimeouts.current[key];
    }

    if (immediate) {
      await saveToDb();
    } else {
      saveTimeouts.current[key] = setTimeout(async () => {
        await saveToDb();
        delete saveTimeouts.current[key];
      }, 1000); // 1 second debounce
    }
  };

  // Helper to update state from DB data
  const updateStateFromKey = useCallback((key: string, val: any) => {
    if (!val) return;
    switch(key) {
      case 'jk_features': 
        setFeatures(val); 
        localStorage.setItem('jk_features', JSON.stringify(val));
        break;
      case 'jk_services': 
        setServices(val); 
        localStorage.setItem('jk_services', JSON.stringify(val));
        break;
      case 'jk_gallery_images': 
        setGalleryImages(val); 
        localStorage.setItem('jk_gallery_images', JSON.stringify(val));
        break;
      case 'jk_hero_image': 
        setHeroImage(val); 
        localStorage.setItem('jk_hero_image', val);
        break;
      case 'jk_testimonials': 
        setTestimonials(val); 
        localStorage.setItem('jk_testimonials', JSON.stringify(val));
        break;
      case 'jk_logo': 
        setLogo(val); 
        localStorage.setItem('jk_logo', val);
        break;
      case 'jk_events': 
        setEvents(val); 
        localStorage.setItem('jk_events', JSON.stringify(val));
        break;
    }
  }, []);

  const fetchGlobalContent = useCallback(async () => {
    try {
      // Use 'content' column instead of 'value'
      const { data, error } = await supabase.from('site_content').select('key, content');
      if (error) {
        if (error.code !== 'PGRST116') {
             console.warn("Sync warning:", error.message);
             setSyncStatus('error');
             setSyncError(error.message);
        }
        return;
      }

      if (data) {
        data.forEach(item => {
          updateStateFromKey(item.key, item.content);
        });
        setSyncStatus('synced');
        setSyncError(null);
      }
    } catch (err: any) {
      console.error("Error loading site content:", err);
      setSyncStatus('error');
      setSyncError(err.message || "Network error");
    }
  }, [updateStateFromKey]);

  // --- Real-time Sync & Polling ---
  useEffect(() => {
    // 1. Initial Fetch
    fetchGlobalContent();

    // 2. Realtime Subscription
    const channel = supabase.channel('content_updates')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'site_content' }, async (payload) => {
         const record = payload.new as any;
         if (!record || !record.key) return;

         // Fetch fresh data to ensure we have the complete JSON object
         // Use 'content' column
         const { data } = await supabase.from('site_content').select('content').eq('key', record.key).single();
         if (data) {
            updateStateFromKey(record.key, data.content);
         }
      })
      .subscribe();

    // 3. Polling Fallback (Every 10 seconds)
    const intervalId = setInterval(() => {
        fetchGlobalContent();
    }, 10000);

    return () => {
      supabase.removeChannel(channel);
      clearInterval(intervalId);
    };
  }, [fetchGlobalContent, updateStateFromKey]);

  // Update Favicon dynamically when logo changes
  useEffect(() => {
    if (logo) {
      let link = document.querySelector("link[rel~='icon']") as HTMLLinkElement;
      if (!link) {
        link = document.createElement('link');
        link.rel = 'icon';
        document.head.appendChild(link);
      }
      link.href = logo;
    }
  }, [logo]);

  // --- Actions ---

  const addBooking = (booking: BookingRecord) => {
    setBookings(prev => {
      const updated = [booking, ...prev];
      localStorage.setItem('jk_bookings', JSON.stringify(updated));
      return updated;
    });
  };

  const updateBookingStatus = (id: string, status: 'Pending' | 'Approved' | 'Rejected') => {
    setBookings(prev => {
      const updated = prev.map(b => b.id === id ? { ...b, status } : b);
      localStorage.setItem('jk_bookings', JSON.stringify(updated));
      return updated;
    });
  };

  const updateFeature = (index: number, feature: FeatureItem) => {
    const newFeatures = [...features];
    newFeatures[index] = feature;
    setFeatures(newFeatures);
    // Use immediate=true if it contains an image URL (heuristic), otherwise debounce
    persist('jk_features', newFeatures, feature.image.startsWith('http'));
  };

  const updateService = (index: number, service: ServiceItem) => {
    const newServices = [...services];
    newServices[index] = service;
    setServices(newServices);
    persist('jk_services', newServices);
  };

  const updateGallery = (images: string[]) => {
    setGalleryImages(images);
    persist('jk_gallery_images', images, true); // Images: Immediate Save
  };

  const updateHeroImage = (url: string) => {
    setHeroImage(url);
    persist('jk_hero_image', url, true); // Images: Immediate Save
  };

  const updateTestimonials = (newTestimonials: Testimonial[]) => {
    setTestimonials(newTestimonials);
    persist('jk_testimonials', newTestimonials);
  };

  const updateLogo = (url: string) => {
    setLogo(url);
    persist('jk_logo', url, true); // Images: Immediate Save
  };

  const updateEvents = (newEvents: EventItem[]) => {
    setEvents(newEvents);
    persist('jk_events', newEvents, true); // Events often involve images: Immediate Save
  };

  return (
    <DataContext.Provider value={{
      features,
      services,
      galleryImages,
      bookings,
      heroImage,
      testimonials,
      logo,
      events,
      syncStatus,
      syncError,
      addBooking,
      updateBookingStatus,
      updateFeature,
      updateService,
      updateGallery,
      updateHeroImage,
      updateTestimonials,
      updateLogo,
      updateEvents
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (!context) throw new Error("useData must be used within a DataProvider");
  return context;
};

import React, { useState, useEffect, useRef } from 'react';
import { GlassCard, GlassButton } from './GlassUI';
import { useData } from '../context/DataContext';
import { Lock, LogOut, Check, X, Edit2, Trash2, Image as ImageIcon, RefreshCw, Loader2, Upload, Plus, Citrus, Calendar, Cloud, CloudOff, Save, AlertTriangle } from 'lucide-react';
import { BookingRecord, EventItem } from '../types';
import { supabase } from '../lib/supabase';

const AdminPanel: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [activeTab, setActiveTab] = useState<'bookings' | 'features' | 'gallery' | 'content' | 'events'>('bookings');

  // Using any[] to accommodate the extra 'row_id' property mapping without changing global types
  const [dbBookings, setDbBookings] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const loginRef = useRef<HTMLDivElement>(null);

  // Upload State
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [uploadTarget, setUploadTarget] = useState<{type: 'feature' | 'gallery' | 'hero' | 'testimonial' | 'logo' | 'event', index?: number} | null>(null);
  const [isUploading, setIsUploading] = useState(false);

  const { 
    features, updateFeature, 
    galleryImages, updateGallery,
    heroImage, updateHeroImage,
    testimonials, updateTestimonials,
    logo, updateLogo,
    events, updateEvents,
    syncStatus,
    syncError 
  } = useData();

  // Scroll handling
  useEffect(() => {
    if (!isAuthenticated) {
      setTimeout(() => {
        loginRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 100);
    } else {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [isAuthenticated]);

  const fetchBookings = async () => {
    setIsLoading(true);
    try {
      const { data, error } = await supabase
        .from('bookings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;

      const mappedData = data ? data.map((b: any) => ({
        ...b,
        id: b.booking_code || b.id, // Display ID (Booking Code)
        row_id: b.id, // Actual Database Primary Key
        venue: b.venue,
        date: b.start_time ? new Date(b.start_time).toLocaleDateString() : 'N/A',
        time: b.start_time ? new Date(b.start_time).toLocaleTimeString() : 'N/A',
        totalPrice: b.price ? parseFloat(b.price) : 0
      })) : [];

      setDbBookings(mappedData);
    } catch (error: any) {
      console.error("Failed to fetch bookings", error);
      if (error.message && error.message.includes("apikey")) {
         alert("Supabase API Key not configured in lib/supabase.ts");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleUpdateStatus = async (rowId: any, status: 'Approved' | 'Rejected') => {
    try {
      // Use Primary Key for updates
      const { error } = await supabase
        .from('bookings')
        .update({ status: status })
        .eq('id', rowId);

      if (error) throw error;

      fetchBookings();
    } catch (e: any) {
      console.error("Update failed:", e);
      alert("Failed to update status: " + (e.message || JSON.stringify(e)));
    }
  };

  const handleDeleteBooking = async (rowId: any, displayId: string) => {
    if (!window.confirm(`Are you sure you want to permanently delete booking ${displayId}?`)) return;

    try {
      // Use exact count to detect RLS silent failures
      const { error, count } = await supabase
        .from('bookings')
        .delete({ count: 'exact' })
        .eq('id', rowId);

      if (error) throw error;

      // If no rows were deleted, it's likely an RLS permission issue
      if (count === 0) {
        alert("Request sent, but no records were deleted.\n\nPossible Cause: Row Level Security (RLS) policies on Supabase are preventing deletion.\n\nSolution: Go to Supabase Dashboard > Table Editor > 'bookings' > Policies, and ensure the 'anon' or 'public' role has DELETE permissions.");
        return;
      }

      // Update local state to remove the deleted item
      setDbBookings(prev => prev.filter(b => b.row_id !== rowId));

    } catch (e: any) {
      console.error("Delete failed:", e);
      const msg = e.message || JSON.stringify(e);
      alert(`Failed to delete: ${msg}`);
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === 'jkpalms' && password === 'jkpalmsandgarden2025') {
      setIsAuthenticated(true);
      fetchBookings();
    } else {
      alert('Invalid Credentials');
    }
  };

  // --- Image Upload Logic ---
  const triggerUpload = (type: 'feature' | 'gallery' | 'hero' | 'testimonial' | 'logo' | 'event', index?: number) => {
    setUploadTarget({ type, index });
    fileInputRef.current?.click();
  };

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!e.target.files || e.target.files.length === 0) return;

    const file = e.target.files[0];
    setIsUploading(true);

    try {
      // Create a unique file name
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(2)}.${fileExt}`;
      const filePath = `${fileName}`;

      // Upload to 'images' bucket
      const { error: uploadError } = await supabase.storage
        .from('images')
        .upload(filePath, file);

      if (uploadError) {
        if (uploadError.message.includes("Bucket not found")) {
          throw new Error("Bucket 'images' not found. Please create a public bucket named 'images' in your Supabase Dashboard.");
        }
        throw uploadError;
      }

      // Get Public URL
      const { data: { publicUrl } } = supabase.storage
        .from('images')
        .getPublicUrl(filePath);

      // Update State based on target
      if (uploadTarget?.type === 'feature' && typeof uploadTarget.index === 'number') {
         const feature = features[uploadTarget.index];
         updateFeature(uploadTarget.index, { ...feature, image: publicUrl });
      } else if (uploadTarget?.type === 'gallery') {
         updateGallery([...galleryImages, publicUrl]);
      } else if (uploadTarget?.type === 'hero') {
         updateHeroImage(publicUrl);
      } else if (uploadTarget?.type === 'logo') {
         updateLogo(publicUrl);
      } else if (uploadTarget?.type === 'testimonial' && typeof uploadTarget.index === 'number') {
         const newTestimonials = [...testimonials];
         newTestimonials[uploadTarget.index] = { ...newTestimonials[uploadTarget.index], avatar: publicUrl };
         updateTestimonials(newTestimonials);
      } else if (uploadTarget?.type === 'event' && typeof uploadTarget.index === 'number') {
         const newEvents = [...events];
         newEvents[uploadTarget.index] = { ...newEvents[uploadTarget.index], image: publicUrl };
         updateEvents(newEvents);
      }

      alert("Image uploaded successfully! Saving to cloud...");
    } catch (error: any) {
      console.error('Upload failed:', error);

      // Handle RLS Errors specifically to guide the user
      if (error.message && (error.message.includes('row-level security') || error.message.includes('permission denied'))) {
        alert(
          "UPLOAD FAILED: Permission Denied\n\n" +
          "This is a security setting in your Supabase project.\n\n" +
          "HOW TO FIX:\n" +
          "1. Go to Supabase Dashboard > Storage > 'images' bucket.\n" +
          "2. Click the 'Policies' tab (or Configuration).\n" +
          "3. Create a new policy for 'INSERT' (Upload) permissions.\n" +
          "4. Allow access for 'anon' or 'public' users.\n" +
          "5. Save policy and try again."
        );
      } else {
        alert(`Upload failed: ${error.message}`);
      }
    } finally {
      setIsUploading(false);
      setUploadTarget(null);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleTestimonialChange = (index: number, field: string, value: string) => {
    const newTestimonials = [...testimonials];
    newTestimonials[index] = { ...newTestimonials[index], [field]: value };
    updateTestimonials(newTestimonials);
  };

  // --- Event Management Logic ---
  const handleAddEvent = () => {
    const newEvent: EventItem = {
      id: Date.now(),
      title: 'New Event',
      date: new Date().toISOString().split('T')[0],
      description: 'Event description goes here...',
      image: 'https://jkpalmandgarden.com/img/exp3.jpg' // Default placeholder
    };
    updateEvents([newEvent, ...events]);
  };

  const handleDeleteEvent = (id: number) => {
    if (window.confirm("Are you sure you want to delete this event?")) {
      updateEvents(events.filter(e => e.id !== id));
    }
  };

  const handleEventChange = (index: number, field: keyof EventItem, value: string) => {
    const newEvents = [...events];
    newEvents[index] = { ...newEvents[index], [field]: value };
    updateEvents(newEvents);
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen pt-24 px-4 flex items-center justify-center">
        <div ref={loginRef} className="w-full max-w-md">
          <GlassCard className="p-8 text-center">
            <div className="bg-emerald-500/20 p-4 rounded-full w-20 h-20 mx-auto flex items-center justify-center mb-6">
              <Lock className="text-emerald-600 w-10 h-10" />
            </div>
            <h2 className="text-2xl font-bold mb-6 text-gray-800 dark:text-white">Admin Access</h2>
            <form onSubmit={handleLogin} className="space-y-4">
              <input
                type="text"
                placeholder="Username"
                value={username}
                onChange={e => setUsername(e.target.value)}
                className="w-full p-3 rounded-xl bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <input
                type="password"
                placeholder="Password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                className="w-full p-3 rounded-xl bg-white/50 dark:bg-black/30 border border-gray-300 dark:border-gray-700 outline-none focus:ring-2 focus:ring-emerald-500"
              />
              <GlassButton type="submit" className="w-full justify-center">Login</GlassButton>
            </form>
          </GlassCard>
        </div>
      </div>
    );
  }

